const resultPath = data.result_path || `/tmp/${wp_id}_result.json`;
const exitCode   = data.exitCode ?? 0;
const stderr     = data.stderr || "";
if (exitCode !== 0) {
  return {
    json: {
      status: "RUNNER_ERROR",
      wp_id, exitCode, stderr,
      result_path: resultPath,
      message: `Runner erreur — exit=${exitCode}. stderr: ${stderr.slice(0,200)}`
    }
  };
}
let resultData = null;
let parseError = null;
try {
  const raw = execSync(`cat ${resultPath}`, { encoding: "utf8" });
  resultData = JSON.parse(raw);
} catch (e) {
  parseError = e.message;
}
if (!resultData) {
  return {
    json: {
      status: "RUNNER_ERROR",
      wp_id, exitCode, stderr, parseError, resultPath,
      message: `Lecture résultat échouée : ${parseError}`
    }
  };
}
const sim  = resultData.simulation || {};
const vrd  = resultData.verdict    || {};
const meta = resultData.meta       || {};
return {
  json: {
    status:            "RUNNER_OK",
    wp_id,
    result_path:       resultPath,
    result_data:       resultData,
    traj_diagn:        sim.traj,
    t_bascule:         sim.t_bascule,
    dC_rel:            sim.dC_rel,
    dI_rel:            sim.dI_rel,
    concordance:       vrd.concordance_attendue,
    robustesse:        vrd.robustesse,
    theta_C_effectif:  meta.theta_C_effectif,
    theta_I_effectif:  meta.theta_I_effectif,
    nc_non_bloquantes: meta.nc_non_bloquantes || [],
    statut_nc:         meta.statut_nc || "OK",
    llm_context:       data.llm_context || {},
    n1_path:           data.n1_path,
    n1_cmd:            data.n1_cmd,
    audit_log:         data.audit_log || {},
    cci_global:        data.cci_global  ?? null,
    cci_result:        data.cci_result  ?? null,
    verdict_cci:       data.verdict_cci ?? null,
    scores_resolus:    data.scores_resolus || {}
  }
};

