};

execSync(`mkdir -p ${Object.values(dirs).join(" ")}`);

const archived = {};

// Écriture via fs.writeFileSync (autorisé via NODE_FUNCTION_ALLOW_BUILTIN=fs)
function writeText(path, content) {
  require("fs").writeFileSync(path, content, "utf8");
}

if (data.result_data) {
  const dst = `${dirs.results}/${wp_id}_result.json`;
