REVISION_MAJEURE = anomalie C4 (narrative smoothing) OU anomalie C1 valeur cle
REJET = anomalie C1 trajectoire OU 3+ anomalies OU CCI<0.50

Reponds UNIQUEMENT en JSON pur sans markdown.`;

const USER = `WP: ${wp_id}
Trajectoire attendue : ${traj_attendue}
Trajectoire simulee : ${sim.traj || "?"}
FR_max : ${sim.FR_max || "?"} | t_bascule : ${sim.t_bascule ?? "null"}
dC_rel : ${sim.dC_rel ?? "null"} | dI_rel : ${sim.dI_rel ?? "null"}

STRESS-TESTS N2 (depuis runner — référence pour contrôle C5) :
${stress_n2_audit}

RAPPORT CONV-A (extrait):
${rapport_md}

Format:
{
  "wp_id": "${wp_id}",
  "audit_c1_c5": {
    "C1": {"statut": "OK|ANOMALIE", "anomalies": [], "detail": "..."},
    "C2": {"statut": "OK|ANOMALIE", "anomalies": [], "detail": "..."},
    "C3": {"statut": "OK|ANOMALIE", "anomalies": [], "detail": "..."},
    "C4": {"statut": "OK|ANOMALIE", "anomalies": [], "detail": "..."},
    "C5": {"statut": "OK|ANOMALIE", "anomalies": [], "detail": "..."}
  },
  "score_checklist": 0,
  "verdict": "CERTIFIE|REVISION_MINEURE|REVISION_MAJEURE|REJET",
  "instructions_revision": [],
  "anomalies": []
}`;

const payload = JSON.stringify({
  model: "claude-sonnet-4-6", max_tokens: 4000,
  system: [{ type: "text", text: SYSTEM, cache_control: { type: "ephemeral" } }], messages: [{ role: "user", content: USER }]
});

let audit_result = null;
let audit_error  = null;
try {
  audit_result = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: "api.anthropic.com", path: "/v1/messages", method: "POST",
      headers: { "Content-Type": "application/json",
        "x-api-key": ANTHROPIC_API_KEY,
        "anthropic-version": "2023-06-01",
        "anthropic-beta": "prompt-caching-2024-07-31" }
    }, (res) => {
      let body = "";
      res.on("data", c => body += c);
      res.on("end", () => {
      try {
        if (res.statusCode !== 200) { reject(new Error(`HTTP ${res.statusCode}: ${body.slice(0,200)}`)); return; }
          const t = JSON.parse(body).content?.[0]?.text || "{}";
          resolve(JSON.parse(t.replace(/```json|```/g,"").trim()));
        } catch(e) { reject(e); }
      });
    });
    req.setTimeout(90000, () => { req.destroy(); reject(new Error("Timeout 90s")); });
  req.on("error", reject);
    req.write(payload); req.end();
  });
} catch(e) { audit_error = e.message; }

const verdict = audit_result?.verdict || "NON_CALCULE";
const need_revision = verdict === "REVISION_MINEURE" || verdict === "REVISION_MAJEURE";

return {
  json: {
    ...data,
    audit_conv_b: audit_result,
    verdict_conv_b: verdict,
    score_checklist: audit_result?.score_checklist || 0,
    anomalies_conv_b: audit_result?.anomalies || [],
    instructions_revision: audit_result?.instructions_revision || [],
    need_revision,
    audit_error,
    message: `CONV-B audit: ${verdict} -- ${audit_result?.score_checklist || "?"}/5`
  }
};

// NOEUD -- Alerte REJET CONV-B
"use strict";
