// NOEUD 12 -- Stress-test N2 (Combinaisons critiques)
// Protocole S3 Niveau 2 : optimiste + pessimiste sur variables sensibles N1
"use strict";
const { execSync } = require("child_process");
const fs = require("fs");

const data    = $input.item.json;
const wp_id   = data.wp_id;
const SCRIPTS = $env.MEPA_SCRIPTS_DIR || "/data/mepa/scripts";

let config_base = {};
try {
  config_base = JSON.parse(fs.readFileSync(`/tmp/${wp_id}_runner_config.json`, "utf8"));
} catch(e) {
  return { json: { ...data, stress_n2: { erreur: "config non disponible" }, robustesse_n2: "NON_CALCULE" } };
}

function perturber(base, direction) {
  const cfg = JSON.parse(JSON.stringify(base));
  const d   = direction === "optimiste" ? 1 : -1;
  // Perturbations standard S3 Niveau 2
  if (cfg.cmd?.Rc  !== undefined) cfg.cmd.Rc  = Math.max(0, Math.min(1, (cfg.cmd.Rc  || 0.5) - d * 0.10));
  if (cfg.cmd?.E   !== undefined) cfg.cmd.E   = Math.max(0, Math.min(1, (cfg.cmd.E   || 0.5) - d * 0.10));
  if (cfg.cmd?.Rn  !== undefined) cfg.cmd.Rn  = Math.max(0, Math.min(1, (cfg.cmd.Rn  || 0)   - d * 0.10));
  return cfg;
}

const resultats_n2 = {};
for (const scenario of ["optimiste", "pessimiste"]) {
  const cfg      = perturber(config_base, scenario);
  const cfg_path = `/tmp/${wp_id}_n2_${scenario}.json`;
  const res_path = `/tmp/${wp_id}_n2_${scenario}_result.json`;
  // Forcer result path dans config
  cfg.result_path = res_path;
  fs.writeFileSync(cfg_path, JSON.stringify(cfg, null, 2));
  let traj_n2 = null;
  try {
    execSync(`/usr/bin/python3 ${SCRIPTS}/mepa_runner_v2_gamma.py ${cfg_path}`,
      { encoding: "utf8", timeout: 60000 });
    const raw = execSync(`cat ${res_path}`, { encoding: "utf8" });
    traj_n2 = JSON.parse(raw).simulation?.traj || "?";
  } catch(e) { traj_n2 = `ERREUR: ${e.message.slice(0,80)}`; }
  resultats_n2[scenario] = traj_n2;
}

const traj_base    = data.traj_diagn;
const bif = Object.values(resultats_n2).filter(t => t && t !== traj_base && !t.startsWith("ERREUR"));
const robustesse_n2 = bif.length === 2 ? "FRAGILE" : bif.length === 1 ? "METASTABLE" : "ROBUSTE";

return {
  json: {
    ...data,
    stress_n2: { traj_base, ...resultats_n2, robustesse_n2, bifurcations: bif },
    robustesse_n2,
    message: `N2: ${robustesse_n2} -- opt=${resultats_n2.optimiste} pes=${resultats_n2.pessimiste}`
  }
};

// NOEUD 13 -- Prediction Popper RF1/RF2/RF3
// Protocole S3 Niveau 3 + S4 : condition d'observation + horizon temporel date
"use strict";
const https = require("https");

const data   = $input.item.json;
const wp_id  = data.wp_id;
const ANTHROPIC_API_KEY = $env.ANTHROPIC_API_KEY;
const meta   = data.result_data?.meta || {};
const sim    = data.result_data?.simulation || {};

const SYSTEM = `Tu identifies la prediction falsifiable MEPA V6.2 applicable.
RF1: maintien paix sociale >15 ans malgre EROI<5 sans techno -- Fenetre 2025-2040
RF2: absence traj (a)/(d) >20 ans malgre E_split>0.7+gamma>0.5 -- Fenetre 20 ans
RF3: complexite croissante >30 ans avec EROI declinant -- Fenetre 2025-2055
Reponds UNIQUEMENT en JSON pur sans markdown.`;

const USER = `WP:${wp_id} | Cas:${meta.cas||""} | Cluster:${data.result_data?.meta?.cluster||""} | Traj:${sim.traj||""} | EROI:${data.result_data?.cmd_base?.EROI||""} | N1:${data.robustesse||""} | N2:${data.result_data?.verdict?.robustesse||""} | E_split:${data.llm_context?.mepa_full_vars?.E_split?.valeur??""} | gamma:${data.llm_context?.mepa_full_vars?.gamma?.valeur??""}
Format: {"prediction_applicable":"RF1|RF2|RF3|AUCUNE","justification":"...","condition_observation":"...","horizon_temporel":"YYYY-YYYY","seuil_refutation":"...","cas_test":"${wp_id}"}`;

let popper_result = null;
let popper_error  = null;
try {
  popper_result = await new Promise((resolve, reject) => {
    const payload = JSON.stringify({
      model: "claude-sonnet-4-6", max_tokens: 600,
      system: SYSTEM, messages: [{ role: "user", content: USER }]
    });
    const req = https.request({
      hostname: "api.anthropic.com", path: "/v1/messages", method: "POST",
      headers: { "Content-Type": "application/json",
        "x-api-key": ANTHROPIC_API_KEY, "anthropic-version": "2023-06-01" }
    }, (res) => {
      let body = "";
      res.on("data", c => body += c);
      res.on("end", () => {
      try {
        if (res.statusCode !== 200) { reject(new Error(`HTTP ${res.statusCode}: ${body.slice(0,200)}`)); return; }
          const t = JSON.parse(body).content?.[0]?.text || "{}";
          resolve(JSON.parse(t.replace(/```json|```/g,"").trim()));
        } catch(e) { reject(e); }
      });
    });
    req.setTimeout(60000, () => { req.destroy(); reject(new Error("Timeout 60s")); });
  req.on("error", reject);
    req.write(payload); req.end();
  });
} catch(e) {
  popper_error = e.message;
  popper_result = { prediction_applicable: "NON_CALCULE", erreur: popper_error };
}

return { json: { ...data, popper: popper_result, popper_error,
  message: `Popper: ${popper_result?.prediction_applicable||"?"} -- ${popper_result?.horizon_temporel||"?"}` }};

// NOEUD 14 -- Certification finale
// Protocole S7 : CCI>=0.75 + N1 robuste + concordance -> WP_CERTIFIE
"use strict";
const data = $input.item.json;
const wp_id = data.wp_id;

const cci_global     = data.cci_global    ?? null;
const robustesse_n1  = data.robustesse    || "NON_CALCULE";
const robustesse_n2  = data.robustesse_n2 || "NON_CALCULE";
const concordance    = data.concordance   ?? false;
const traj_diagn     = data.traj_diagn    || "?";
const traj_attendue  = data.result_data?.meta?.trajectoire_attendue || "?";
const verdict_conv_b = data.verdict_conv_b || "NON_CALCULE";

// Criteres de certification S7 du Guide Methodologique
const cci_ok         = cci_global !== null && cci_global >= 0.75;
const n1_ok          = ["ROBUSTE","METASTABLE"].includes(robustesse_n1);
const concordance_ok = concordance === true;
const conv_b_ok      = verdict_conv_b === "CERTIFIE"; // REVISION sans rebouclage → WP_EXPLORATOIRE

let statut = "WP_EXPLORATOIRE";
const raison = [];
if (cci_ok && n1_ok && concordance_ok && conv_b_ok) {
  statut = "WP_CERTIFIE";
} else {
  if (!cci_ok)         raison.push(`CCI=${cci_global?.toFixed(3)??"null"} < 0.75`);
  if (!n1_ok)          raison.push(`N1=${robustesse_n1}`);
  if (!concordance_ok) raison.push(`Concordance=NON (${traj_diagn} != ${traj_attendue})`);
  if (!conv_b_ok)      raison.push(`CONV-B=${verdict_conv_b}`);
}

const _certDate = new Date().toISOString().split("T")[0]; // YYYY-MM-DD

return {
  json: {
    ...data,
    date_codage_pipeline: _certDate,
    certification: {
      statut, cci_global, robustesse_n1, robustesse_n2, concordance,
      verdict_conv_b, raison_non_certifie: raison,
      popper: data.popper || null, scores_resolus: data.scores_resolus || {},
      date_certification: _certDate
    },
    statut_global: statut,
    message: `[CERTIFICATION] ${wp_id} -> ${statut} [${_certDate}]${raison.length ? " : "+raison.join(" | ") : ""}`
  }
};

// ============================================================================
// NŒUD 15 V2 — Archivage Final [Multi-passes]
// ============================================================================
// Modifications vs V1 :
//   - Tous les fichiers archivés portent le suffixe _sim_N dans leur nom
//   - Un fichier de synthèse multi-passes est généré après la dernière passe
//     (détecté via num_passe === nb_passes_total)
//   - Rétrocompatibilité : si num_passe absent, comportement V1 identique
// ============================================================================

"use strict";
const fs = require("fs");
const { execSync } = require("child_process");

const data    = $input.item.json;
const wp_id   = data.wp_id;
const BASE    = $env.MEPA_OUTPUT_DIR || "/data/mepa/outputs";
const cluster = (data.result_data?.meta?.cluster || "CX").replace(/[^A-Z0-9]/g, "");
const cert    = data.certification || {};
const sim     = data.result_data?.simulation || {};

// ── Suffixe de passe ─────────────────────────────────────────────────────────
const num_passe     = data.num_passe     ?? null;
const sim_label     = data.sim_label     ?? null;  // "sim_1", "sim_2", ...
const nb_passes     = data.nb_passes_total ?? null;
const passe_label   = data.passe_label   ?? null;
const zone          = data.zone_stratification ?? "LOI PHYSIQUE";

// Préfixe fichier : WP-F1-1_sim_1 ou WP-F1-1 (V1)
const file_prefix = sim_label ? `${wp_id}_${sim_label}` : wp_id;

// ── Répertoires ──────────────────────────────────────────────────────────────
const dirs = {
  results:      `${BASE}/cluster_${cluster}/results`,
  rapports:     `${BASE}/cluster_${cluster}/rapports`,
  passeports:   `${BASE}/passeports`,
  sensitivity:  `${BASE}/sensitivity`,
  certification:`${BASE}/certification`,
};
execSync(`mkdir -p ${Object.values(dirs).join(" ")}`);

const w = (path, content) => { fs.writeFileSync(path, content, "utf8"); return path; };
const archived = {};

// ── Archivage des fichiers de cette passe ────────────────────────────────────
if (data.result_data)
  archived.result    = w(`${dirs.results}/${file_prefix}_result.json`,
                          JSON.stringify(data.result_data, null, 2));

if (data.rapport_n1)
  archived.rapport_n1 = w(`${dirs.sensitivity}/${file_prefix}_n1.json`,
                           JSON.stringify(data.rapport_n1, null, 2));

if (data.stress_n2)
  archived.stress_n2  = w(`${dirs.sensitivity}/${file_prefix}_n2.json`,
                           JSON.stringify(data.stress_n2, null, 2));

if (data.rapport_md)
  archived.rapport_md = w(`${dirs.rapports}/${file_prefix}_rapport.md`,
                           data.rapport_md);

if (data.cci_result)
  archived.cci        = w(`${dirs.certification}/${file_prefix}_cci.json`,
                           JSON.stringify(data.cci_result, null, 2));

if (data.conv_b_data)
  archived.conv_b     = w(`${dirs.certification}/${file_prefix}_conv_b.json`,
                           JSON.stringify(data.conv_b_data, null, 2));

if (data.audit_conv_b)
  archived.audit_b    = w(`${dirs.certification}/${file_prefix}_audit_b.json`,
                           JSON.stringify(data.audit_conv_b, null, 2));

if (data.popper)
  archived.popper     = w(`${dirs.certification}/${file_prefix}_popper.json`,
                           JSON.stringify(data.popper, null, 2));

// ── Passeport de passe ───────────────────────────────────────────────────────
const passeport_passe = {
  ...(data.passeport || {}),
  num_passe,
  sim_label,
  passe_label,
  zone_stratification: zone,
  certification_v2: {
    statut:         cert.statut,
    cci_global:     cert.cci_global,
    kappa_sa:       data.cci_result?.kappa_sa ?? null,
    robustesse_n1:  cert.robustesse_n1,
    robustesse_n2:  cert.robustesse_n2,
    concordance:    cert.concordance,
    scores_resolus: cert.scores_resolus,
    verdict_conv_b: cert.verdict_conv_b,
    popper:         cert.popper,
    raison_non_certifie: cert.raison_non_certifie,
    generated_at:   new Date().toISOString(),
  }
};
archived.passeport = w(
  `${dirs.passeports}/${file_prefix}_passeport.json`,
  JSON.stringify(passeport_passe, null, 2)
);

// ── Passeport compact CONV-D ─────────────────────────────────────────────────
const popper_rf1 = data.popper?.prediction_applicable === "RF1"
  ? data.popper?.condition_observation : null;
const popper_rf2 = data.popper?.prediction_applicable === "RF2"
  ? data.popper?.condition_observation : null;

const passeport_compact = {
  wp_id,
  sim_label,
  num_passe,
  passe_label,
  zone,
  cluster,
  sa:            data.result_data?.meta?.sa ?? null,
  traj_attendue: data.result_data?.meta?.trajectoire_attendue || "?",
  traj_diagn:    sim.traj || "?",
  concordant:    cert.concordance ?? false,
  robustesse:    cert.robustesse_n1 || "?",
  t_b:           sim.t_bascule ?? null,
  dC_rel:        sim.dC_rel ?? null,
  dI_rel:        sim.dI_rel ?? null,
  CCI:           cert.cci_global ?? null,
  RF1:           popper_rf1,
  RF2:           popper_rf2,
  p6_final:      data.result_data?.params?.p6 ?? null,
  statut_cert:   cert.statut || "WP_EXPLORATOIRE",
  alertes:       data.anomalies_conv_b || [],
};
archived.passeport_compact = w(
  `${dirs.certification}/${file_prefix}_passeport_compact.json`,
  JSON.stringify(passeport_compact)
);

// ── Synthèse multi-passes (générée sur la DERNIÈRE passe uniquement) ─────────
let synthese_passes = null;
// ── Compteur atomique de passes terminées ────────────────────────────────
// Chaque exécution N15 (une par passe, en parallèle) incrémente ce compteur.
// La première passe à atteindre nb_passes déclenche la consolidation N16.
// Mécanisme fichier (append atomique) pour éviter les race conditions.
const counter_path = `/tmp/${wp_id}_pass_done_counter`;
let pass_count = 0;
try {
  // Append "1\n" — chaque passe écrit une ligne
  fs.appendFileSync(counter_path, "1\n", "utf8");
  // Compter les lignes = nombre de passes terminées
  pass_count = fs.readFileSync(counter_path, "utf8").trim().split("\n").filter(Boolean).length;
} catch(e) {
  pass_count = num_passe ?? 1;
}
// Guard null : si nb_passes est null/0, ne jamais déclencher N16
const toutes_passes_terminees = (
  nb_passes !== null && nb_passes > 0 && pass_count >= nb_passes
);

if (toutes_passes_terminees && num_passe !== null && nb_passes !== null) {

  // Lire tous les passeports compacts des passes précédentes
  const all_passeports = [];
  for (let i = 1; i <= nb_passes; i++) {
    const path_compact = `${dirs.certification}/${wp_id}_sim_${i}_passeport_compact.json`;
    try {
      all_passeports.push(JSON.parse(fs.readFileSync(path_compact, "utf8")));
    } catch (_) {
      // passe manquante — ignorer
    }
  }

  // Résumé des trajectoires diagnostiquées par passe
  const trajs_par_passe = all_passeports.map(p => ({
    sim:         p.sim_label,
    passe_label: p.passe_label,
    traj:        p.traj_diagn,
    concordant:  p.concordant,
    robustesse:  p.robustesse,
    CCI:         p.CCI,
  }));

  const trajs_uniques = [...new Set(all_passeports.map(p => p.traj_diagn))];
  const nb_concordants = all_passeports.filter(p => p.concordant).length;
  const cci_values = all_passeports.map(p => p.CCI).filter(v => v !== null);
  const cci_moyen  = cci_values.length
    ? cci_values.reduce((a, b) => a + b, 0) / cci_values.length
    : null;

  const robustesse_globale =
    trajs_uniques.length === 1 ? "ROBUSTE" :
    trajs_uniques.length === 2 ? "MÉTASTABLE" : "FRAGILE";

  synthese_passes = {
    wp_id,
    zone,
    nb_passes,
    nb_passes_lues: all_passeports.length,
    generated_at: new Date().toISOString(),
    robustesse_globale,
    trajectoires_uniques: trajs_uniques,
    concordance_taux: `${nb_concordants}/${nb_passes}`,
    cci_moyen: cci_moyen !== null ? Math.round(cci_moyen * 10000) / 10000 : null,
    passes: trajs_par_passe,
  };

  archived.synthese_passes = w(
    `${dirs.certification}/${wp_id}_synthese_passes.json`,
    JSON.stringify(synthese_passes, null, 2)
  );
}

// ── Retour ───────────────────────────────────────────────────────────────────
return {
  json: {
    status:                "ARCHIVE_CERTIFIE",
    pass_count,
    toutes_passes_terminees,
    wp_id,
    sim_label,
    num_passe,
    nb_passes_total:       nb_passes,
    passe_label,
    statut_certification:  cert.statut,
    cci_global:            cert.cci_global,
    robustesse_n1:         cert.robustesse_n1,
    concordance:           cert.concordance,
    verdict_conv_b:        data.verdict_conv_b,
    archived,
    passeport_compact,
    synthese_passes,
    message: synthese_passes
      ? `[WF2 COMPLET] ${wp_id} | ${nb_passes} passes | robustesse=${synthese_passes.robustesse_globale} | CCI_moy=${synthese_passes.cci_moyen}`
      : `[WF2 PASSE ${num_passe}/${nb_passes}] ${wp_id} → ${cert.statut}`,
  }
};

// NŒUD CONV-E — Codage historique des 6 variables continues
// Position : après Nœud B (décodage JSON), avant Nœud 2 (audit C1-C13)
// Double aveugle garanti : ce nœud écrit variables[k].valeur
// Le Nœud 8a (CONV-B) filtre activement ces valeurs — aucune contamination
// Correctif architecture — 2026-03-16

"use strict";
const https = require("https");
const data  = $input.item.json;
const wp_id = data.wp_id;
const ANTHROPIC_API_KEY = $env.ANTHROPIC_API_KEY;

// ── Extraire le contexte de la fiche ────────────────────────────────────────
const cas             = data.cas             || "";
const periode         = data.periode         || "";
const cluster         = data.cluster         || "";
const traj_attendue   = data.trajectoire_attendue || "";
const sa              = data.sa              ?? null;
const sa_type         = data.sa_type_todd    || "";
const vars_fiche      = data.variables       || {};
const sources         = data.sources_utilisees || [];
const defi            = data.defi_mepa       || "";
const alertes         = data.alertes_conv_a  || [];

// ── Variables hardcodées (EROI, A_r_ne, Sa) — ne pas recoder ───────────────
const vars_hardcodes = {};
for (const [k, v] of Object.entries(vars_fiche)) {
  if (v.valeur !== null && v.valeur !== undefined &&
      (String(v.source_id || "").includes("hardcod") ||
       String(v.source_id || "").includes("normative") ||
       String(v.source_id || "").includes("V6.2") ||
       String(v.origine  || "").toUpperCase().includes("HARDCOD") ||
       String(v.source_id || "").includes("Todd"))) {
    vars_hardcodes[k] = v.valeur;
  }
}

// ── Variables à coder — celles avec valeur: null ────────────────────────────
const vars_a_coder = Object.fromEntries(
  Object.entries(vars_fiche)
    .filter(([k, v]) => v.valeur === null || v.valeur === undefined)
    .map(([k, v]) => [k, {
      echelle:            v.echelle,
      origine:            v.origine,
      source_id:          v.source_id,
      niveau_source:      v.niveau_source,
      sanity_check:       v.sanity_check,
      valeur_normative:   v.valeur_normative_v62
    }])
);

// ── Commandes actuelles (valeurs normatives — à mettre à jour post-codage) ──
const cmd_actuel = data.commandes || {};

// ── Sources disponibles ──────────────────────────────────────────────────────
const sources_str = sources.slice(0, 8).map(s =>
  typeof s === "object"
    ? `[${s.id}] ${s.titre} (${s.type}) — variables: ${(s.variables_concernees || []).join(", ")}`
    : String(s)
).join("\n");

// ── Chargement CONV-E.md depuis disque (V7 — grilles d'ancrage V7 incluses) ──
// ── Chargement CONV-E.md depuis disque ──────────────────────────────────────
const _fs_conv_e = require('fs');
const _scripts_dir = $env.MEPA_SCRIPTS_DIR || '/data/mepa/scripts';
const SYSTEM = (() => {
  let base;
  try {
    base = _fs_conv_e.readFileSync(`${_scripts_dir}/CONV-E.md`, 'utf8');
  } catch(_) {
    base = "Tu es CONV-E, l'Historien-Codeur MEPA. Code les variables null en JSON valide.";
  }
  return base + "\n\n=== INSTRUCTION DE FORMAT STRICTE ===\nTa réponse doit commencer IMMÉDIATEMENT par '{' et ne contenir RIEN d'autre qu'un objet JSON valide. Aucune phrase de confirmation, aucun préambule, aucun texte avant ou après le JSON. Ne dis jamais 'Je confirme' ou toute autre formule introductive.";
})();
const USER = `WP : ${wp_id} | Cas : ${cas} | Période : ${periode} | Cluster : ${cluster}
Trajectoire attendue : ${traj_attendue} | Sa : ${sa} (${sa_type})
Défi MEPA : ${defi.slice(0, 300)}
Alertes : ${JSON.stringify(alertes).slice(0, 200)}

SOURCES DISPONIBLES :
${sources_str}

VARIABLES À CODER (valeur = null) :
${JSON.stringify(vars_a_coder, null, 2).slice(0, 3000)}

COMMANDES ACTUELLES (valeurs normatives à mettre à jour) :
${JSON.stringify({
  E: cmd_actuel.E, gamma: cmd_actuel.gamma, R: cmd_actuel.R,
  Mob: cmd_actuel.Mob, Rc: cmd_actuel.Rc, Rn: cmd_actuel.Rn
})}

CONDITIONS INITIALES ACTUELLES :
${JSON.stringify(data.conditions_initiales || {})}

Produis un JSON avec exactement cette structure :
{
  "codeur": "CONV-E",
  "date_codage": "${new Date().toISOString().split("T")[0]}",
  "variables_codees": {
    "E_split": {"valeur": <float>, "justification": "<2-3 phrases avec γ si gamma, indicateurs chiffrés>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "gamma":   {"valeur": <float>, "justification": "<utilise γ dans le texte>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "A_d_eff": {"valeur": <float>, "justification": "<indicateurs chiffrés obligatoires>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "A_r_c":   {"valeur": <float>, "justification": "<source explicite>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "Cs":      {"valeur": <float>, "justification": "<source explicite>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}},
    "L_t":     {"valeur": <float>, "justification": "<source explicite>", "sanity_check": {"indicateur": "<source>", "valeur_indicateur": "<valeur>", "coherence": "CONFIRMÉ|À VÉRIFIER|DIVERGENCE"}}
  },
  "commandes_mises_a_jour": {
    "E": <float E_split>, "gamma": <float gamma>,
    "R": <float normalisé A_d_eff>, "Mob": <float Cs>,
    "Rc": <float A_r_c>, "Rn": <float A_r_ne hardcodé>
  },
  "L0_mis_a_jour": <float L_t>,
  "resume_coherence": "<3-5 phrases — compatibilité scores avec trajectoire attendue et cluster>"
}`;

const payload = JSON.stringify({
  model: "claude-sonnet-4-6",
  max_tokens: 8000,
  system: [{ type: "text", text: SYSTEM, cache_control: { type: "ephemeral" } }],
  messages: [{ role: "user", content: USER }]
});

// ── Appel API Anthropic (L3 prompt caching) ─────────────────────────────────
const conv_e_result = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: "api.anthropic.com",
    path: "/v1/messages",
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": ANTHROPIC_API_KEY,
      "anthropic-version": "2023-06-01",
      "anthropic-beta": "prompt-caching-2024-07-31",
      "Content-Length": Buffer.byteLength(payload)
    }
  }, (res) => {
    let body = "";
    res.on("data", c => body += c);
    res.on("end", () => {
      try {
        if (res.statusCode !== 200) { reject(new Error(`HTTP ${res.statusCode}: ${body.slice(0,200)}`)); return; }
        const raw = JSON.parse(body).content?.[0]?.text || "{}";
        // Extraire le premier bloc JSON valide même si du texte précède/suit
        const clean = raw.replace(/```json|```/g, "").trim();
        const jsonMatch = clean.match(/\{[\s\S]*\}/);
        if (!jsonMatch) { reject(new Error(`Aucun JSON trouvé dans la réponse: ${clean.slice(0,200)}`)); return; }
        resolve(JSON.parse(jsonMatch[0]));
      } catch(e) {
        reject(new Error(`Parse CONV-E: ${e.message} | raw: ${body.slice(0,200)}`));
      }
    });
  });
  req.setTimeout(240000, () => { req.destroy(); reject(new Error("Timeout 240s")); });
  req.on("error", reject);
  req.write(payload);
  req.end();
});

// ── Injecter les valeurs codées dans la fiche ────────────────────────────────
const vars_codees  = conv_e_result.variables_codees  || {};
const cmd_updates  = conv_e_result.commandes_mises_a_jour || {};
const l0_update    = conv_e_result.L0_mis_a_jour;

// Mettre à jour variables[k].valeur
const vars_updated = { ...vars_fiche };
for (const [k, v] of Object.entries(vars_codees)) {
  if (vars_updated[k]) {
    vars_updated[k] = {
      ...vars_updated[k],
      valeur:       v.valeur,
      justification: v.justification,
      sanity_check: { ...vars_updated[k].sanity_check, ...v.sanity_check },
      codeur:       "CONV-E",
      date_codage:  conv_e_result.date_codage
    };
  }
}

// Mettre à jour les commandes — mapping sélectif CONV-E
// RÈGLE V6.2 : E, gamma, Rc, Rn → mapping libre depuis variables codées
// R (A_d_eff) et Mob (Cs) → NE PAS écraser les valeurs normatives corpus
// T, Ref, Pop, EROI → structurels, jamais modifiés par CONV-E
const CMD_MAPPING_LIBRE = ["E", "gamma", "Rc", "Rn"];
const cmd_updated = { ...cmd_actuel };
for (const key of CMD_MAPPING_LIBRE) {
  if (cmd_updates[key] !== undefined && cmd_updates[key] !== null) {
    cmd_updated[key] = cmd_updates[key];
  }
}
// R et Mob : logguer la valeur CONV-E mais préserver la valeur normative
const r_conv_e   = cmd_updates["R"]   ?? null;
const mob_conv_e = cmd_updates["Mob"] ?? null;
if (r_conv_e !== null) {
  console.error("[CONV-E] cmd.R propose par CONV-E = " + r_conv_e + " -- valeur normative corpus preservee : " + cmd_actuel.R);
}
if (mob_conv_e !== null) {
  console.error("[CONV-E] cmd.Mob propose par CONV-E = " + mob_conv_e + " -- valeur normative corpus preservee : " + cmd_actuel.Mob);
}

// Mettre à jour L0 dans conditions_initiales
const ci_updated = { ...(data.conditions_initiales || {}) };
if (l0_update !== undefined && l0_update !== null) {
  ci_updated.L0 = l0_update;
}

// ── Retourner la fiche enrichie ──────────────────────────────────────────────
// Champs pipeline (non transmis dans la fiche racine — évite erreur C9)
const _conv_e_meta = {
  conv_e_raw:       conv_e_result,
  resume_coherence: conv_e_result.resume_coherence || "",
  nb_vars_codees:   Object.keys(vars_codees).length
};

return {
  json: {
    ...data,
    // Champs fiche — autorisés par RACINE_AUTORISEES
    variables:            vars_updated,
    commandes:            cmd_updated,
    conditions_initiales: ci_updated,
    statut:               "CODAGE CONV-E — EN ATTENTE AUDIT CONV-B",
    date_codage:          conv_e_result.date_codage || new Date().toISOString().split("T")[0],
    codeur:               "CONV-E",
    // Champs pipeline — préfixe _ exclu de la fiche mais lisibles par les nœuds suivants
    _conv_e_meta,
    _pipeline_message: `[CONV-E] ${wp_id} — ${Object.keys(vars_codees).length} variables codées`
  }
};

// NŒUD C — Nettoyage /tmp/ entre passes
// Supprime tous les fichiers /tmp/{wp_id}_* de la passe précédente
// Garantit l'isolation entre passes successives sur le même WP
"use strict";
const { execSync } = require("child_process");
const data  = $input.item.json;
const wp_id = data.wp_id || "WP-INCONNU";

let cleaned = [];
let errors  = [];

// Liste des fichiers /tmp/ créés par le pipeline
const patterns = [
  `_runner_config.json`,
  `_result.json`,
  `_n1_sensitivity.json`,
  `_fiche_conv_b.json`,
  `_fiche_conv_e_kappa.json`,
  `_cci_result.json`,
  `_passeport.json`,
  `_n2_optimiste.json`,
  `_n2_pessimiste.json`,
  `_n2_optimiste_result.json`,
  `_n2_pessimiste_result.json`,
  `_revision_counter.txt`
];

for (const suffix of patterns) {
  const path = `/tmp/${wp_id}${suffix}`;
  try {
    execSync(`rm -f ${path}`);
    cleaned.push(path);
  } catch(e) {
    errors.push(`${path}: ${e.message.slice(0,50)}`);
  }
}

return {
  json: {
    ...data,
    cleanup: { cleaned: cleaned.length, errors },
    message: `[CLEANUP] ${wp_id} — ${cleaned.length} fichiers /tmp/ supprimés`
  }
};

// ============================================================================
// NŒUD 16 — Consolidation Multi-passes [Post-toutes-passes]
// ============================================================================
// Position   : connecté sur N15 (déclenché à chaque passe)
//              Guard return [] si !toutes_passes_terminees → n8n n'émet rien
//              → s'exécute réellement UNE SEULE FOIS sur la dernière passe,
//              quand tous les fichiers ont été archivés par N15.
//
// Entrée     : payload N15 (porte wp_id, zone, nb_passes_total,
//              toutes_passes_terminees, pass_count)
//              + tous les fichiers archivés par N15 sur disque
//
// Sorties disque :
//   /data/mepa/outputs/cluster_XX/results/{wp_id}_consolidation.json
//   /data/mepa/outputs/cluster_XX/rapports/{wp_id}_consolidation.md
//
// En cas de passe manquante (runner échoué) :
//   → Consolide les passes disponibles + flag passes_manquantes[]
//
// Sources lues :
//   certification/{wp_id}_sim_N_passeport_compact.json  (trajectoires, CCI, robustesse)
//   cluster_XX/results/{wp_id}_sim_N_result.json         (F/R, stress N1/N2)
//   certification/{wp_id}_sim_N_cci.json                 (accord inter-codeurs par var)
//   sensitivity/{wp_id}_sim_N_n1.json                    (sensibilité paramétrique)
// ============================================================================

"use strict";
const fs = require("fs");
const { execSync } = require("child_process");

const data         = $input.item.json;
const wp_id        = data.wp_id        || "WP-INCONNU";
const zone         = data.zone_stratification || "LOI PHYSIQUE";
const nb_passes    = data.nb_passes_total ?? 0;
const num_passe    = data.num_passe ?? null;
  const toutes_passes_terminees = data.toutes_passes_terminees ?? false;

  // ── Guard : ne consolider QUE sur la dernière passe ──────────────────────
  // N15 déclenche N16 à chaque passe (connexion permanente).
  // N16 filtre via toutes_passes_terminees transmis par N15.
  // Si false → return [] : n8n n'émet pas d'item, la chaîne s'arrête ici.
  // Si true  → exécuter la consolidation complète.
  // Guard double : toutes_passes_terminees=false OU nb_passes invalide
  if (!toutes_passes_terminees || !nb_passes || nb_passes < 1) {
    return [];
  }

  const BASE         = $env.MEPA_OUTPUT_DIR || "/data/mepa/outputs";
const cluster_raw  = data.llm_context?.cluster || data.cluster || "CX";
const cluster      = cluster_raw.replace(/[^A-Z0-9]/g, "");

// ── Répertoires ──────────────────────────────────────────────────────────────
const dirs = {
  results:      `${BASE}/cluster_${cluster}/results`,
  rapports:     `${BASE}/cluster_${cluster}/rapports`,
  passeports:   `${BASE}/passeports`,
  sensitivity:  `${BASE}/sensitivity`,
  certification:`${BASE}/certification`,
};
execSync(`mkdir -p ${Object.values(dirs).join(" ")}`);

// ── Helpers lecture sécurisée ─────────────────────────────────────────────────
function readJSON(path) {
  try { return JSON.parse(fs.readFileSync(path, "utf8")); }
  catch (_) { return null; }
}

// ── Lecture des N passes ──────────────────────────────────────────────────────
const passes_lues       = [];
const passes_manquantes = [];

for (let i = 1; i <= nb_passes; i++) {
  const sim = `sim_${i}`;
  const prefix_cert   = `${dirs.certification}/${wp_id}_${sim}`;
  const prefix_result = `${dirs.results}/${wp_id}_${sim}`;
  const prefix_sens   = `${dirs.sensitivity}/${wp_id}_${sim}`;

  const compact  = readJSON(`${prefix_cert}_passeport_compact.json`);
  const result   = readJSON(`${prefix_result}_result.json`);
  const cci      = readJSON(`${prefix_cert}_cci.json`);
  const n1       = readJSON(`${prefix_sens}_n1.json`);

  // Une passe est considérée manquante si le passeport compact est absent
  if (!compact) {
    passes_manquantes.push({ num: i, sim, raison: "passeport_compact introuvable" });
    continue;
  }

  // Extraire les métriques clés du result runner
  const sim_data  = result?.simulation || {};
  const vrd_data  = result?.verdict    || {};
  const meta_data = result?.meta       || {};
  const cmd_data  = result?.cmd_base   || {};

  // Résumé N1/N2 depuis le result runner (stress embarqué)
  const stress_n1 = result?.stress_n1 || {};
  const stress_n2 = result?.stress_n2 || [];
  const trajs_n2  = [...new Set(stress_n2.map(s => s.traj).filter(Boolean))];

  // Résumé CCI par variable
  const cci_details = cci?.details || [];
  const cci_par_var = Object.fromEntries(
    cci_details.map(d => [d.variable, {
      val_e:    d.val_a,
      val_b:    d.val_b,
      accord:   d.accord,
      action:   d.action,
    }])
  );

  // Résumé N1 sensitivity
  const n1_verdict       = n1?.verdict_n1 || null;
  const n1_vars_sensibles = n1?.variables_sensibles || [];
  const n1_params_sensibles = n1?.params_sensibles || [];

  passes_lues.push({
    num_passe:        i,
    sim_label:        sim,
    passe_label:      compact.passe_label    || null,
    zone:             compact.zone           || zone,
    // Trajectoire
    traj_attendue:    compact.traj_attendue,
    traj_diagn:       compact.traj_diagn,
    concordant:       compact.concordant,
    robustesse_n1:    compact.robustesse,
    statut_cert:      compact.statut_cert,
    // Métriques runner
    FR_max:           sim_data.FR_max        ?? null,
    FR_final:         sim_data.FR_final      ?? null,
    t_bascule:        sim_data.t_bascule     ?? null,
    dC_rel:           sim_data.dC_rel        ?? null,
    dI_rel:           sim_data.dI_rel        ?? null,
    I_final:          sim_data.I_final       ?? null,
    C_final:          sim_data.C_final       ?? null,
    // Stress N1 (depuis result runner)
    n1_opt_traj:      stress_n1.optimiste?.traj  || null,
    n1_pes_traj:      stress_n1.pessimiste?.traj || null,
    n1_pes_dI_rel:    stress_n1.pessimiste?.dI_rel ?? null,
    trajs_set_n1:     vrd_data.trajs_set_n1  || [],
    // Stress N2 (depuis result runner)
    trajs_n2_uniques: trajs_n2,
    bifurcations_n2:  trajs_n2.filter(t => t !== compact.traj_diagn),
    // CCI
    CCI_global:       compact.CCI            ?? null,
    CCI_par_variable: cci_par_var,
    // N1 sensitivity externe
    n1_verdict,
    n1_vars_sensibles,
    n1_params_sensibles,
    // Commandes appliquées dans cette passe
    cmd_effectifs: {
      E:     cmd_data.E     ?? null,
      gamma: cmd_data.gamma ?? null,
      Rc:    cmd_data.Rc    ?? null,
      T:     cmd_data.T     ?? null,
      R:     cmd_data.R     ?? null,
      EROI_start: cmd_data.EROI_start ?? null,
      EROI_end:   cmd_data.EROI_end   ?? null,
    },
    L0_effectif:      meta_data.y0_normalise?.[1] ?? null,
    // Popper
    RF1: compact.RF1 || null,
    RF2: compact.RF2 || null,
    p6_final: compact.p6_final ?? null,
  });
}

// ── Calculs de synthèse ───────────────────────────────────────────────────────
const nb_lus        = passes_lues.length;
const nb_manquantes = passes_manquantes.length;
const nb_concordants = passes_lues.filter(p => p.concordant).length;

// Toutes les trajectoires diagnostiquées
const toutes_trajs  = passes_lues.map(p => p.traj_diagn).filter(Boolean);
const trajs_uniques = [...new Set(toutes_trajs)];

// Robustesse globale inter-passes
const robustesse_globale =
  trajs_uniques.length === 0 ? "NON_CALCULE" :
  trajs_uniques.length === 1 ? "ROBUSTE"     :
  trajs_uniques.length === 2 ? "MÉTASTABLE"  : "FRAGILE";

// Trajectoire majoritaire
const traj_count = {};
toutes_trajs.forEach(t => traj_count[t] = (traj_count[t] || 0) + 1);
const traj_majoritaire = Object.entries(traj_count)
  .sort((a, b) => b[1] - a[1])[0]?.[0] || null;

// CCI agrégé (moyenne des CCI globaux disponibles)
const cci_vals = passes_lues.map(p => p.CCI_global).filter(v => v !== null);
const cci_moyen = cci_vals.length
  ? Math.round(cci_vals.reduce((a, b) => a + b, 0) / cci_vals.length * 10000) / 10000
  : null;
const cci_min = cci_vals.length ? Math.min(...cci_vals) : null;
const cci_max = cci_vals.length ? Math.max(...cci_vals) : null;

// Stabilité des CCI par variable (accord CONV-E/CONV-B cohérent entre passes ?)
const vars_suivies = ["E_split", "gamma", "A_d_eff", "A_r_c", "Cs", "L_t"];
const cci_par_var_consolide = {};
for (const v of vars_suivies) {
  const vals_e = passes_lues.map(p => p.CCI_par_variable?.[v]?.val_e).filter(x => x !== null && x !== undefined);
  const vals_b = passes_lues.map(p => p.CCI_par_variable?.[v]?.val_b).filter(x => x !== null && x !== undefined);
  const accords = passes_lues.map(p => p.CCI_par_variable?.[v]?.accord).filter(x => x !== null && x !== undefined);
  if (vals_e.length === 0) continue;
  const mean = arr => arr.length ? Math.round(arr.reduce((a,b)=>a+b,0)/arr.length * 100) / 100 : null;
  cci_par_var_consolide[v] = {
    val_e_moy:    mean(vals_e),
    val_b_moy:    mean(vals_b),
    taux_accord:  accords.length ? Math.round(accords.filter(Boolean).length / accords.length * 100) : null,
    nb_passes:    vals_e.length,
  };
}

// Bifurcations N2 inter-passes (quelles passes ont des bifurcations ?)
const passes_avec_bifurc = passes_lues
  .filter(p => p.bifurcations_n2.length > 0)
  .map(p => ({ sim: p.sim_label, bifurcations: p.bifurcations_n2 }));

// FR_max moyen et écart-type (sensibilité à la configuration)
const fr_vals = passes_lues.map(p => p.FR_max).filter(v => v !== null);
const fr_moy  = fr_vals.length ? Math.round(fr_vals.reduce((a,b)=>a+b,0)/fr_vals.length * 10000)/10000 : null;
const fr_std  = fr_vals.length > 1
  ? Math.round(Math.sqrt(fr_vals.map(v => (v-fr_moy)**2).reduce((a,b)=>a+b,0)/fr_vals.length) * 10000)/10000
  : null;

// ── Objet consolidation JSON ──────────────────────────────────────────────────
const consolidation = {
  // Identité
  wp_id,
  cluster,
  zone_stratification: zone,
  nb_passes_attendues: nb_passes,
  nb_passes_lues:      nb_lus,
  nb_passes_manquantes:nb_manquantes,
  passes_manquantes,
  generated_at:        new Date().toISOString(),

  // Verdict global
  verdict: {
    robustesse_globale,
    trajectoire_majoritaire:   traj_majoritaire,
    trajectoires_uniques:      trajs_uniques,
    concordance_taux:          `${nb_concordants}/${nb_lus}`,
    concordance_totale:        nb_concordants === nb_lus && nb_lus > 0,
    flag_passes_manquantes:    nb_manquantes > 0,
  },

  // CCI consolidé
  cci: {
    moyen:  cci_moyen,
    min:    cci_min,
    max:    cci_max,
    ecart:  cci_vals.length > 1 ? Math.round((cci_max - cci_min) * 10000)/10000 : null,
    seuil_certif: 0.75,
    toutes_certifiees: cci_vals.length > 0 && cci_min >= 0.75,
    par_variable: cci_par_var_consolide,
  },

  // Métriques runner consolidées
  runner: {
    FR_max_moyen:   fr_moy,
    FR_max_stddev:  fr_std,
    FR_max_min:     fr_vals.length ? Math.min(...fr_vals) : null,
    FR_max_max:     fr_vals.length ? Math.max(...fr_vals) : null,
    I_final_values: passes_lues.map(p => ({ sim: p.sim_label, I_final: p.I_final })),
  },

  // Robustesse N2
  n2: {
    passes_avec_bifurcations: passes_avec_bifurc,
    nb_passes_robustes_n2:    passes_lues.filter(p => p.bifurcations_n2.length === 0).length,
  },

  // Détail par passe (tableau compact)
  passes: passes_lues.map(p => ({
    sim:          p.sim_label,
    passe_label:  p.passe_label,
    traj_diagn:   p.traj_diagn,
    concordant:   p.concordant,
    robustesse:   p.robustesse_n1,
    FR_max:       p.FR_max,
    t_b:          p.t_bascule,
    CCI:          p.CCI_global,
    n1_pes_traj:  p.n1_pes_traj,
    bifurc_n2:    p.bifurcations_n2,
    cmd_E:        p.cmd_effectifs?.E,
    cmd_gamma:    p.cmd_effectifs?.gamma,
    cmd_Rc:       p.cmd_effectifs?.Rc,
    L0:           p.L0_effectif,
  })),
};

// ── Markdown de synthèse ──────────────────────────────────────────────────────
const taux_concordance = `${nb_concordants}/${nb_lus}`;
const cci_str = cci_moyen !== null ? `${cci_moyen} (min=${cci_min}, max=${cci_max})` : "N/C";
const manq_str = nb_manquantes > 0
  ? `\n> ⚠ **${nb_manquantes} passe(s) manquante(s)** : ${passes_manquantes.map(p => p.sim).join(", ")}\n`
  : "";

const lignes_passes = passes_lues.map(p => {
  const bifurc = p.bifurcations_n2.length > 0 ? `⚡ N2: ${p.bifurcations_n2.join(",")}` : "N2: stable";
  const n1pes  = p.n1_pes_traj && p.n1_pes_traj !== p.traj_diagn ? ` ⚡ N1pes→${p.n1_pes_traj}` : "";
  return `| ${p.sim_label} | ${p.passe_label || "-"} | ${p.traj_diagn} | ${p.concordant ? "✓" : "✗"} | ${p.robustesse_n1} | ${p.FR_max ?? "N/C"} | ${p.CCI_global ?? "N/C"} | ${bifurc}${n1pes} |`;
}).join("\n");

// CCI par variable
const lignes_cci = Object.entries(cci_par_var_consolide).map(([v, d]) =>
  `| ${v} | ${d.val_e_moy ?? "N/C"} | ${d.val_b_moy ?? "N/C"} | ${d.taux_accord !== null ? d.taux_accord + "%" : "N/C"} |`
).join("\n");

const rapport_md = `# Consolidation Multi-passes — ${wp_id}

**Zone :** ${zone} | **Passes :** ${nb_lus}/${nb_passes} lues | **Généré :** ${new Date().toISOString().split("T")[0]}
${manq_str}
---

## Verdict global

| Critère | Valeur |
|---|---|
| Robustesse inter-passes | **${robustesse_globale}** |
| Trajectoire majoritaire | \`${traj_majoritaire}\` |
| Trajectoires distinctes | ${trajs_uniques.join(" / ")} |
| Concordance | ${taux_concordance} passes concordantes |
| CCI moyen | ${cci_str} |
| Toutes passes CCI certifiées (≥0.75) | ${consolidation.cci.toutes_certifiees ? "✓ OUI" : "✗ NON"} |
| FR_max moyen | ${fr_moy ?? "N/C"} (σ=${fr_std ?? "N/C"}) |

---

## Détail par passe

| Passe | Label | Trajectoire | Concord. | Robustesse | FR_max | CCI | N2 / N1 pessimiste |
|---|---|---|---|---|---|---|---|
${lignes_passes}

---

## CCI par variable (accord CONV-E / CONV-B consolidé)

| Variable | Val. moy CONV-E | Val. moy CONV-B | Taux accord |
|---|---|---|---|
${lignes_cci || "| N/C | — | — | — |"}

---

## Robustesse N2 inter-passes

- Passes avec bifurcations N2 : ${passes_avec_bifurc.length > 0 ? passes_avec_bifurc.map(p => `${p.sim} (→${p.bifurcations.join(",")})`).join(", ") : "aucune"}
- Passes robustes N2 : ${consolidation.n2.nb_passes_robustes_n2}/${nb_lus}

---

## Notes pour CONV-D

${robustesse_globale === "ROBUSTE"
  ? `Toutes les passes convergent vers \`${traj_majoritaire}\`. Le diagnostic est robuste à la variation paramétrique.`
  : robustesse_globale === "MÉTASTABLE"
  ? `Le système est en zone de transition : deux trajectoires possibles selon le paramétrage. Documenter en S3.`
  : `Fragmentation diagnostique sur ${trajs_uniques.length} trajectoires distinctes. Investigation approfondie requise.`}
${nb_manquantes > 0 ? `\n⚠ ${nb_manquantes} passe(s) non archivées — les résultats ci-dessus sont partiels.` : ""}
`;

// ── Archivage ─────────────────────────────────────────────────────────────────
const w = (path, content) => { fs.writeFileSync(path, content, "utf8"); return path; };

const path_json = w(`${dirs.results}/${wp_id}_consolidation.json`,  JSON.stringify(consolidation, null, 2));
const path_md   = w(`${dirs.rapports}/${wp_id}_consolidation.md`,   rapport_md);

// ── Retour ────────────────────────────────────────────────────────────────────
return {
  json: {
    status:               "CONSOLIDATION_OK",
    wp_id,
    zone,
    nb_passes_lues:       nb_lus,
    nb_passes_manquantes: nb_manquantes,
    passes_manquantes,
    robustesse_globale,
    trajectoire_majoritaire: traj_majoritaire,
    trajectoires_uniques: trajs_uniques,
    concordance_taux:     taux_concordance,
    cci_moyen,
    cci_certifie:         consolidation.cci.toutes_certifiees,
    FR_max_moyen:         fr_moy,
    FR_max_stddev:        fr_std,
    paths: { json: path_json, md: path_md },
    consolidation,
    message: `[N16 CONSOLIDATION] ${wp_id} | ${zone} | ${nb_lus}/${nb_passes} passes`
      + (nb_manquantes > 0 ? ` | ⚠ ${nb_manquantes} manquante(s)` : "")
      + ` | robustesse=${robustesse_globale} | CCI_moy=${cci_moyen}`,
  }
};
